import React, { useEffect, useState, useCallback } from 'react';
import { useTable, useSortBy, useGlobalFilter, usePagination } from 'react-table';

const ProjectFunc = () => {

    // State to store the projectId from the query parameter
  const [projectId, setProjectId] = useState(null);
  const [outflows, setOutflows] = useState([]);
  const [isLoading, setIsLoading] = useState(true); // New state to track loading status


  useEffect(() => {
    // Parse the query parameter from the URL
    const params = new URLSearchParams(window.location.search);
    const projectIdParam = params.get('projectId');

    if (projectIdParam) {
      // Set the projectId in the component's state
      setProjectId(projectIdParam);
    }
  }, []);

  
  const fetchData = useCallback(async () => {
    try {
      const [outflowsResponse] = await Promise.all([
        fetch('http://localhost:8081/outflowsAPI').then((response) => response.json()),
      ]);
      filtered = outflowsResponse;
      setOutflows(outflowsResponse.filter((res) => res.project === projectId));
      setIsLoading(false);
    } catch (error) {
      console.log('Error fetching data:', error);
      setIsLoading(false);
    }
  }, [projectId]);

  useEffect(() => {
    fetchData();
  }, [fetchData]);

  console.log('outflows', outflows);
  console.log('projectid', projectId);

  
  
  const columns = React.useMemo(
    () => [
      { Header: 'ID', accessor: 'prid' },
      { Header: 'Name', accessor: 'name' },
      { Header: 'Description', accessor: 'description' },
      { Header: 'Projected Material Cost', accessor: 'prmatcost' },
      { Header: 'Projected Labor Cost', accessor: 'prlabcost' },
      { Header: 'Sale', accessor: 'sale' },
      { Header: 'Real Material Cost', accessor: 'realmatcost' },
      { Header: 'Real Labor Cost', accessor: 'reallabcost' },
      { Header: 'Total Cost', accessor: 'totalcost' },
   
    ],
    []
  );
  
  const {
    getTableProps,
    getTableBodyProps,
    headerGroups,
    page,
    prepareRow,
    state: { pageIndex, pageSize, globalFilter },
    gotoPage,
    nextPage,
    previousPage,
    canNextPage,
    canPreviousPage,
    setPageSize,
    setGlobalFilter,
  } = useTable(
    {
      columns,
      data: outflows,
      initialState: {
        pageIndex: 0,
        pageSize: 10,
      },
    },
    useGlobalFilter,
    useSortBy,
    usePagination
  );


  if (isLoading) {
    return <div>Loading...</div>;
  }

  return (
    <div>

      <div className="search">
        <input
          type="text"
          palue={globalFilter || ''}
          onChange={(e) => setGlobalFilter(e.target.palue)}
          placeholder="Search..."
        />
      </div>
      <table {...getTableProps()} className="purchase-table">
        <thead>
          {headerGroups.map((headerGroup) => (
            <tr {...headerGroup.getHeaderGroupProps()}>
              {headerGroup.headers.map((column) => (
                <th {...column.getHeaderProps(column.getSortByToggleProps())}>
                  {column.render('Header')}
                  <span>{column.isSorted ? (column.isSortedDesc ? ' 🔽' : ' 🔼') : ''}</span>
                </th>
              ))}
            </tr>
          ))}
        </thead>
        <tbody {...getTableBodyProps()}>
          {page.map((row) => {
            prepareRow(row);
            return (
              <React.Fragment key={row.getRowProps().key}>
                <tr {...row.getRowProps()}>
                  {row.cells.map((cell) => (
                    <td {...cell.getCellProps()}>{cell.render('Cell')}</td>
                  ))}
                </tr>
                
              </React.Fragment>
            );
          })}
        </tbody>
      </table>
      <div>
      <button onClick={() => previousPage()} disabled={!canPreviousPage}>
  Previous
</button>
<button onClick={() => nextPage()} disabled={!canNextPage}>
  Next
</button>
<span>
  Page{' '}
  <strong>
    {pageIndex + 1} of {Math.ceil(outflows.length / pageSize)}
  </strong>{' '}
</span>
<span>
  | Go to page:{' '}
  <input
    type="number"
    defaultValue={pageIndex + 1} // Corrected the typo here
    onChange={(e) => {
      const page = e.target.value ? Number(e.target.value) - 1 : 0;
      gotoPage(page);
    }}
    style={{ width: '50px' }}
  />
</span>
<select
  value={pageSize}
  onChange={(e) => {
    setPageSize(Number(e.target.value));
  }}
>
  {[10, 25, 50].map((pageSize) => (
    <option key={pageSize} value={pageSize}>
      Show {pageSize}
    </option>
  ))}
</select>

      </div>
    </div>
  );
};

export default ProjectFunc;
